/*
 * Deadlock Prevention: Circular Wait Prevention using Resource Ordering
 * =========================================================================
 * This program demonstrates how imposing a total ordering on resource types
 * prevents circular wait - one of the four necessary conditions for deadlock.
 * 
 * Resource Order: Scanner(1) < Printer(2) < Tape(3) < Disk(4)
 * A process can only request resources in strictly increasing order.
 */

#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_RESOURCES 10
#define MAX_PROCESSES 5

// Resource types with assigned order numbers
typedef enum {
 SCANNER = 1,
 PRINTER = 2,
 TAPE = 3,
 DISK = 4
} ResourceType;

// Structure to represent a resource
typedef struct {
 ResourceType type;
 bool in_use;
 int order; // F(R) - the order number
} Resource;

// Structure for a process
typedef struct {
 int pid;
 ResourceType held[MAX_RESOURCES];
 int held_count;
 ResourceType requested[MAX_RESOURCES];
 int request_count;
} Process;

// Global resource table with ordering
Resource resources[] = {
 {SCANNER, false, 1},
 {PRINTER, false, 2},
 {TAPE, false, 3},
 {DISK, false, 4}
};

#define NUM_RESOURCES (sizeof(resources) / sizeof(resources[0]))

// Get order number for a resource type
int get_resource_order(ResourceType type) {
 for (int i = 0; i < NUM_RESOURCES; i++) {
 if (resources[i].type == type) {
 return resources[i].order;
 }
 }
 return -1;
}

// Get resource name for display
const char* get_resource_name(ResourceType type) {
 switch(type) {
 case SCANNER: return "Scanner";
 case PRINTER: return "Printer";
 case TAPE: return "Tape";
 case DISK: return "Disk";
 default: return "Unknown";
 }
}

/*
 * Check if a request follows the increasing order rule
 * Returns true if request is valid (no deadlock possible)
 */
bool check_resource_ordering(Process *p, ResourceType new_request) {
 // If process holds no resources, any request is valid
 if (p->held_count == 0) {
 return true;
 }

 // Find the highest order number of currently held resources
 int max_held_order = 0;
 for (int i = 0; i < p->held_count; i++) {
 int order = get_resource_order(p->held[i]);
 if (order > max_held_order) {
 max_held_order = order;
 }
 }

 // New request must have higher order than all held resources
 int new_order = get_resource_order(new_request);

 printf(" Process P%d holds resources up to order %d, "
 "requesting order %d: ", 
 p->pid, max_held_order, new_order);

 if (new_order > max_held_order) {
 printf("ALLOWED (increasing order)\n");
 return true;
 } else {
 printf("DENIED (would violate ordering)\n");
 return false;
 }
}

/*
 * Allocate resource to process if ordering is maintained
 */
bool allocate_resource(Process *p, ResourceType request) {
 // Check if resource is available
 Resource *res = NULL;
 for (int i = 0; i < NUM_RESOURCES; i++) {
 if (resources[i].type == request && !resources[i].in_use) {
 res = &resources[i];
 break;
 }
 }

 if (!res) {
 printf(" Resource %s not available\n", get_resource_name(request));
 return false;
 }

 // Check ordering constraint
 if (!check_resource_ordering(p, request)) {
 printf(" Request DENIED to prevent circular wait\n");
 return false;
 }

 // Allocate resource
 res->in_use = true;
 p->held[p->held_count++] = request;
 printf(" SUCCESS: Allocated %s to P%d\n", get_resource_name(request), p->pid);

 return true;
}

/*
 * Release all resources held by a process
 */
void release_all_resources(Process *p) {
 printf("P%d releasing all resources: ", p->pid);
 for (int i = 0; i < p->held_count; i++) {
 ResourceType type = p->held[i];
 for (int j = 0; j < NUM_RESOURCES; j++) {
 if (resources[j].type == type) {
 resources[j].in_use = false;
 printf("%s ", get_resource_name(type));
 break;
 }
 }
 }
 printf("\n");
 p->held_count = 0;
}

/*
 * Demonstrate prevention of circular wait
 */
void demonstrate_prevention() {
 printf("\n========================================\n");
 printf("DEADLOCK PREVENTION: RESOURCE ORDERING\n");
 printf("========================================\n\n");

 printf("Resource Ordering: Scanner(1) < Printer(2) < Tape(3) < Disk(4)\n");
 printf("Rule: A process can only request resources in INCREASING order\n\n");

 // Create processes
 Process p1 = {.pid = 1, .held_count = 0};
 Process p2 = {.pid = 2, .held_count = 0};

 // Scenario 1: Valid request sequence
 printf("=== Scenario 1: VALID request sequence ===\n");
 printf("P1 requests Scanner (order 1):\n");
 allocate_resource(&p1, SCANNER);

 printf("P1 requests Printer (order 2) - higher than Scanner (1):\n");
 allocate_resource(&p1, PRINTER);

 printf("P1 requests Disk (order 4) - higher than Printer (2):\n");
 allocate_resource(&p1, DISK);

 release_all_resources(&p1);

 // Scenario 2: Invalid request (would cause circular wait)
 printf("\n=== Scenario 2: INVALID request (prevents deadlock) ===\n");
 printf("P2 holds Printer (order 2):\n");
 allocate_resource(&p2, PRINTER);

 printf("P2 requests Scanner (order 1) - LOWER than Printer (2):\n");
 allocate_resource(&p2, SCANNER);

 // Correct way: release Printer first, then request Scanner
 printf("\n=== Correct approach: Release then request ===\n");
 release_all_resources(&p2);
 printf("P2 releases Printer, now requests Scanner:\n");
 allocate_resource(&p2, SCANNER);

 printf("\n========================================\n");
 printf("By enforcing increasing order, circular wait\n");
 printf("is impossible - deadlock is prevented!\n");
 printf("========================================\n");
}

int main() {
 demonstrate_prevention();
 return 0;
}

/*
 * Time Complexity: O(n) where n = number of resource types
 * Space Complexity: O(n) for resource tracking
 * 
 * Why this prevents deadlock:
 * If circular wait existed: P0→R0→P1→R1→...→Pn→Rn→P0
 * Then F(R0) < F(R1) < ... < F(Rn) < F(R0)
 * This is impossible (transitive inequality leads to F(R0) < F(R0))
 */
